$ErrorActionPreference = 'Stop';
& {
	try {
		$params = @{
			LiteralPath = 'C:\Windows\System32\IntegratedServicesRegionPolicySet.json';
			Encoding = 'Utf8';
		};
		$o = Get-Content @params | ConvertFrom-Json;
		$o.policies | ForEach-Object -Process {
			if( $_.guid -eq '{1bca278a-5d11-4acf-ad2f-f9ab6d7f93a6}' ) {
				$_.defaultState = 'enabled';
			}
		};
		$o | ConvertTo-Json -Depth 9 | Out-File @params;
	} catch {
		$_;
	}
} *>&1 | Out-String -Width 1KB -Stream >> 'C:\Windows\Setup\Scripts\MakeEdgeUninstallable.log';

$out = & "$env:windir\System32\powercfg.exe" /DuplicateScheme 'e9a42b02-d5df-448d-aa00-03f14749eb61';
if( $out -match '\s([a-f0-9-]{36})\s' ) {
    & "$env:windir\System32\powercfg.exe" /SetActive $Matches[1];
} else {
    'Could not enable Ultimate Performance power scheme.' | Write-Warning;
}

# Instalacao offline do Chrome a partir do pendrive
$drives = [System.IO.DriveInfo]::GetDrives() | Where-Object { $_.DriveType -eq 'Removable' -or $_.DriveType -eq 'Fixed' };
foreach( $drive in $drives ) {
    $file = Join-Path $drive.RootDirectory 'extras\chrome_installer.exe';
    if( Test-Path $file ) {
        Start-Process -FilePath $file -ArgumentList '/silent /install' -Wait;
        break;
    }
}

# Instalacao offline do Visual C++ Redistributable a partir do pendrive
$drives = [System.IO.DriveInfo]::GetDrives() | Where-Object { $_.DriveType -eq 'Removable' -or $_.DriveType -eq 'Fixed' };
foreach( $drive in $drives ) {
    $file = Join-Path $drive.RootDirectory 'extras\vc_redist.x64.exe';
    if( Test-Path $file ) {
        Start-Process -FilePath $file -ArgumentList '/quiet /norestart' -Wait;
        break;
    }
}

foreach( $drive in [System.IO.DriveInfo]::GetDrives() ) {
    if( $found = Join-Path -Path $drive.RootDirectory -ChildPath 'sources\sxs' -Resolve -ErrorAction 'SilentlyContinue' ) {
        Enable-WindowsOptionalFeature -Online -FeatureName 'NetFx3' -Source $found -NoRestart;
        return;
    }
}
